import { jsonSchemaToType } from "./json.ts"

const localRefMatcher = /^#\/\$defs\/(.+)$/

interface RefContext {
	has: (name: string) => boolean
	get: (name: string) => Type
}

// NB: parsing is synchronous and single-threaded, so a simple stack of the
// currently in-scope `$defs` registries is sufficient to resolve `$ref`s that
// appear at any depth within the schema currently being parsed.
const refContextStack: RefContext[] = []

const currentRefContext = (): RefContext | undefined =>
	refContextStack[refContextStack.length - 1]

/**
 * Parse `jsonSchema` with its root-level `$defs` (if any) registered so that
 * any nested `$ref: "#/$defs/<name>"` can be resolved. Definitions are parsed
 * lazily and memoized, which is what allows recursive (self-referential)
 * `$ref`s to terminate.
 */
export const parseWithRootDefs = (
	jsonSchema: JsonSchema | boolean,
	parse: () => Type
): Type => {
	const $defs =
		typeof jsonSchema === "object" && jsonSchema !== null ?
			(jsonSchema as JsonSchema.Meta).$defs
		:	undefined

	if ($defs === undefined) return parse()

	const memo: Record<string, Type> = {}
	const context: RefContext = {
		has: name => name in $defs,
		get: name => {
			if (!(name in memo)) {
				// parse the definition within this context so that sibling and
				// self `$ref`s resolve against the same `$defs`
				refContextStack.push(context)
				try {
					memo[name] = jsonSchemaToType($defs[name])
				} finally {
					refContextStack.pop()
				}
			}
			return memo[name]
		}
	}

	refContextStack.push(context)
	try {
		return parse()
	} finally {
		refContextStack.pop()
	}
}

export const parseRefJsonSchema = (jsonSchema: JsonSchema.Ref): Type => {
	const match = localRefMatcher.exec(jsonSchema.$ref)
	if (match === null) throwParseError(writeJsonSchemaUnsupportedRefMessage())

	const name = match[1]
	const context = currentRefContext()

	// Validate resolvability eagerly (at parse time) without forcing the
	// definition to be parsed, so recursive `$ref`s don't infinitely recurse.
	if (context === undefined || !context.has(name)) {
		throwParseError(
			writeJsonSchemaUnresolvableRefMessage(`#/$defs/${name}`)
		)
	}

	const jsonSchemaRefValidator = (data: unknown, ctx: Traversal) => {
		const resolved = context.get(name)
		return resolved.allows(data) ?
				true
			:	ctx.reject({
					expected: resolved.description,
					actual: printable(data)
				})
	}
	return type.unknown.narrow(jsonSchemaRefValidator)
}
