import { jsonSchemaToType } from "./json.ts"

/**
 * Parse a JSON Schema `if`/`then`/`else` conditional.
 *
 * - `if` is evaluated silently (a failure to match is not itself an error)
 * - when `if` matches, the data must also match `then` (if present)
 * - when `if` does not match, the data must match `else` (if present)
 * - `if` on its own, or `then`/`else` without `if`, impose no constraints
 */
export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema.Conditional
): Type | undefined => {
	// `then`/`else` without `if` are a no-op
	if (!("if" in jsonSchema)) return

	const hasThen = "then" in jsonSchema
	const hasElse = "else" in jsonSchema

	// `if` on its own imposes no constraints
	if (!hasThen && !hasElse) return

	const ifValidator = jsonSchemaToType(jsonSchema.if)
	const thenValidator =
		hasThen ? jsonSchemaToType(jsonSchema.then!) : undefined
	const elseValidator =
		hasElse ? jsonSchemaToType(jsonSchema.else!) : undefined

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		if (ifValidator.allows(data)) {
			if (thenValidator !== undefined && !thenValidator.allows(data)) {
				return ctx.reject({
					expected: `${thenValidator.description} (since it matched the 'if' schema)`,
					actual: printable(data)
				})
			}
		} else if (elseValidator !== undefined && !elseValidator.allows(data)) {
			return ctx.reject({
				expected: `${elseValidator.description} (since it did not match the 'if' schema)`,
				actual: printable(data)
			})
		}
		return true
	}
	return type.unknown.narrow(jsonSchemaConditionalValidator)
}
