/**
 * Parse the JSON Schema dependency keywords:
 *
 * - `dependentRequired`: `{ trigger: [requiredKey, ...] }` — if `trigger` is
 *   present, each listed key must also be present.
 * - `dependentSchemas`: `{ trigger: schema }` — if `trigger` is present, the
 *   data must also validate against `schema`.
 * - `dependencies` (draft-07): a merge of the two, where array values behave
 *   like `dependentRequired` and schema values like `dependentSchemas`.
 *
 * Dependencies only constrain objects; non-objects satisfy them vacuously.
 */
export const parseDependenciesJsonSchema = (
	jsonSchema: JsonSchema.Object
): Type | undefined => {
	const dependentRequired: Record<string, readonly string[]> = {
		...jsonSchema.dependentRequired
	}
	const dependentSchemas: Record<string, JsonSchema | boolean> = {
		...jsonSchema.dependentSchemas
	}

	if ("dependencies" in jsonSchema && jsonSchema.dependencies !== undefined) {
		for (const [key, value] of Object.entries(jsonSchema.dependencies)) {
			if (Array.isArray(value)) dependentRequired[key] = value
			else dependentSchemas[key] = value as JsonSchema | boolean
		}
	}

	const hasDependentRequired = Object.keys(dependentRequired).length > 0
	const hasDependentSchemas = Object.keys(dependentSchemas).length > 0
	if (!hasDependentRequired && !hasDependentSchemas) return

	const parsedDependentSchemas = Object.entries(dependentSchemas).map(
		([trigger, schema]) => [trigger, jsonSchemaToType(schema)] as const
	)

	const jsonSchemaDependenciesValidator = (data: unknown, ctx: Traversal) => {
		if (
			typeof data !== "object" ||
			data === null ||
			Array.isArray(data)
		)
			// dependencies only apply to objects
			return true

		for (const [trigger, requiredKeys] of Object.entries(
			dependentRequired
		)) {
			if (!(trigger in data)) continue
			for (const requiredKey of requiredKeys) {
				if (!(requiredKey in data)) {
					ctx.reject({
						path: [requiredKey],
						expected: `present (required when '${trigger}' is present)`,
						actual: "missing"
					})
				}
			}
		}

		for (const [trigger, schema] of parsedDependentSchemas) {
			if (trigger in data && !schema.allows(data)) {
				ctx.reject({
					expected: `${schema.description} (required when '${trigger}' is present)`,
					actual: printable(data)
				})
			}
		}

		return !ctx.hasError()
	}
	return type.unknown.narrow(jsonSchemaDependenciesValidator)
}
